client_script:
frappe.web_form.after_load = function () {
    set_flight_price();
};

// Trigger when user changes flight
frappe.web_form.on("flight", function () {
    set_flight_price();
});

function set_flight_price() {
    let flight = frappe.web_form.get_value("flight");

    if (!flight) {
        frappe.web_form.set_value("flight_price", "");
        return;
    }

    frappe.call({
        method: "frappe.client.get",
        args: {
            doctype: "Airplane Flight",
            name: flight
        },
        callback: function (r) {
            if (r.message && r.message.flight_price) {
                frappe.web_form.set_value("flight_price", r.message.flight_price);
            } else {
                frappe.web_form.set_value("flight_price", "");
            }
        }
    });
}
